UPDATE customers SET customerType = 'standard' WHERE customerType = 'retail_offering';

UPDATE customers SET customerType = 'retail_offering'
WHERE externalId IN (
  SELECT DISTINCT customerExternalId FROM billing_items
  WHERE description LIKE '%SmileTel supplied NBN voice and internet bundle%'
     OR description LIKE '%Site Bundle%'
     OR description LIKE '%SmileTel supplied mobile broadband%'
     OR description LIKE 'ST- NBN%'
     OR description LIKE 'ST-NBN%'
);
